onClick:
{{
  bulkUpdateAPI.run(
    // 1. Map the Staged Changes to the Backend Body
    {
      "user_id": appsmith.user.id,
      "items": Object.entries(appsmith.store.stagedChanges || {}).map(([id, change]) => ({
        id: Number(id),
        type: change.type,
        status: change.status,
        reason: change.reason,
        report_id: getReportDetails.data.summary.id
      }))
    },
    // 2. SUCCESS: Clean up and Refresh
    () => {
      showAlert('All Changes Saved & Report Finalized!', 'success');
      storeValue('stagedChanges', {}); // 🧹 Clear staging store
      storeValue('denoms', {});        // 🧹 Clear denominations store
      getReportDetails.run();          // 🔄 Refresh the data from DB
    },
    // 3. ERROR: Keep the changes in store if it fails!
    () => {
      showAlert('Save Failed: ' + bulkUpdateAPI.data.error, 'error');
    }
  )
}}
